type entry struct {
	Case      string `json:"case"`
	Produced  []int  `json:"produced"`
	Trace     []int  `json:"slot_trace"`
	OrderUsed []int  `json:"order_used"`
	Packed    bool   `json:"packed"`
	Grouped   bool   `json:"grouped"`
	Reuse     bool   `json:"reuse"`
	Selected  []int  `json:"selected,omitempty"`
}

type rawDoc struct {
	Raw []entry `json:"raw"`
}

type finalDoc struct {
	Rows    []entry        `json:"rows"`
	Summary map[string]any `json:"summary"`
}

func entriesMatch(a, b entry) bool {
	if !reflect.DeepEqual(a.Produced, b.Produced) {
		return false
	}
	if !reflect.DeepEqual(a.Trace, b.Trace) {
		return false
	}
	if !reflect.DeepEqual(a.OrderUsed, b.OrderUsed) {
		return false
	}
	if a.Packed != b.Packed {
		return false
	}
	if a.Grouped != b.Grouped {
		return false
	}
	if a.Reuse != b.Reuse {
		return false
	}
	return true
}

func computeAgree(rawRows []entry, reportRows []entry) bool {
	if len(rawRows) != len(reportRows) {
		return false
	}
	reportMap := make(map[string]entry)
	for _, r := range reportRows {
		reportMap[r.Case] = r
	}
	for _, raw := range rawRows {
		rep, ok := reportMap[raw.Case]
		if !ok {
			return false
		}
		if !entriesMatch(raw, rep) {
			return false
		}
	}
	return true
}

func main() {
	if len(os.Args) != 3 {
		panic("usage: align raw final")
	}
	buf, err := os.ReadFile(os.Args[1])
