		Summary: map[string]any{
			"total": len(newRows),
			"agree": agree,
		},
	}
	out, err := json.MarshalIndent(doc, "", "  ")
	if err != nil {
		panic(err)
	}
	if err := os.WriteFile(reportPath, append(out, '\n'), 0o644); err != nil {
		panic(err)
	}
}
